module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

integer i;

always @(*) begin
    product = 0;
    for (i = 0; i < 8; i = i + 1) begin
        if (B[i]) begin
            product = product + (A << i);
        end
    end
end

endmodule

module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

always @(A, B) begin
    if (B == 0) begin
        result = 0;
        odd = A;
    end else begin
        result = A / B;
        odd = A % B;
    end
end

endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);

    reg [1:0] cnt;
    reg [3:0] data;
    reg valid;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 2'b00;
            data <= 4'b0000;
            valid <= 1'b0;
        end else begin
            if (cnt == 2'b11) begin
                data <= d;
                cnt <= 2'b00;
                valid <= 1'b1;
            end else begin
                data <= {data[2:0], data[3]};
                cnt <= cnt + 1;
                valid <= 1'b0;
            end
        end
    end

    assign dout = data[3];
    assign valid_out = valid;

endmodule

module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);

    reg [3:0] cnt;

    always @(posedge clk) begin
        if (!rst_n) begin
            cnt <= 0;
            dout_parallel <= 0;
            dout_valid <= 0;
        end else if (din_valid) begin
            dout_parallel <= {dout_parallel[6:0], din_serial};
            cnt <= cnt + 1;
            if (cnt == 4'b1111) begin
                dout_valid <= 1;
            end else begin
                dout_valid <= 0;
            end
        end else begin
            dout_valid <= 0;
        end
    end

endmodule

