module add1 (
    input a,
    input b,
    input Cin,
    output y,
    output Co
);
    assign y = ((~a) & (~b) & Cin | (~a) & b & (~Cin) | a & (~b) & (~Cin) | (a & b & Cin));
    assign Co = ((~a & b & Cin) | (a & ~b & Cin) | (a & b & ~Cin) | (a & b & Cin));

endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

reg prev_a;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        prev_a <= 1'b0;
        rise <= 1'b0;
        down <= 1'b0;
    end else begin
        prev_a <= a;
        rise <= (prev_a == 1'b0 && a == 1'b1) ? 1'b1 : 1'b0;
        down <= (prev_a == 1'b1 && a == 1'b0) ? 1'b1 : 1'b0;
    end
end

endmodule

module counter_12 (
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n)
            out <= 4'b0000;
        else if(valid_count==1) begin
            if(out==4'd11) out <= 4'b0000; else out <= out + 1;
        end
    end

endmodule

module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

    reg res_valid_reg;
    reg start_cnt;
    reg [3:0] cnt;
    reg [8:0] neg_divisor;
    reg dividend_sign;
    reg divisor_sign;
    reg [7:0] dividend_abs;
    reg [7:0] divisor_abs;
    reg [17:0] SR;

    wire [9:0] sub_result;
    wire carry_out;
    wire mux_out;
    assign sub_result = {SR[17], SR} + {neg_divisor[8], neg_divisor};
    assign carry_out = ~sub_result[9];
    assign mux_out = (sub_result[8:0] & {9{carry_out}}) | (sub_result[8:0] & ~{9{carry_out}});
    always @(posedge clk or posedge rst) begin
        if(rst) begin
            res_valid_reg <= 1'b0;
            start_cnt <= 1'b0;
            cnt <= 1'b0;
            neg_divisor <= 1'b0;
            dividend_sign <= 1'b0;
            divisor_sign <= 1'b0;
            dividend_abs <= 1'b0;
            divisor_abs <= 1'b0;
        end else begin
            if(opn_valid && !res_valid_reg) begin
                dividend_sign <= sign ? dividend[7] : 1'b0;
                divisor_sign <= sign ? divisor[7] : 1'b0;
                dividend_abs <= sign ? (dividend[7] ? (~dividend + 1'b1) : dividend) : dividend;
                divisor_abs <= sign ? (divisor[7] ? (~divisor + 1'b1) : divisor) : divisor;
                SR <= {dividend_abs, 1'b0};
                neg_divisor <= ~(divisor_abs) + 1'b1;
                cnt <= 1'b1;
                start_cnt <= 1'b1;
            end else if(start_cnt) begin
                if(cnt[3]) begin
                    cnt <= 1'b0;
                    start_cnt <= 1'b0;
                    SR <= {mux_out, SR[17:1]};
                end else begin
                    cnt <= cnt + 1'b1;
                    SR <= {mux_out, SR[17:1]};
                end
            end
        end
    end
    always @(posedge clk or posedge rst) begin
        if(rst) begin
            res_valid_reg <= 1'b0;
        end else begin
            if(cnt == 4'd8) begin
                res_valid_reg <= 1'b1;
            end else if(res_valid_reg && res_ready) begin
                res_valid_reg <= 1'b0;
            end else begin
                res_valid_reg <= res_valid_reg;
            end
        end
    end
    assign res_valid = res_valid_reg;
    assign result = {SR[17:9], SR[8:1]};
endmodule

