module cla_4bit(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout,
    output p_group,
    output g_group
);
    wire [3:0] p; 
    wire [3:0] g; 
    wire [4:0] c; 


    assign p = a ^ b;
    assign g = a & b;


    assign c[0] = cin;
    assign c[1] = g[0] | (p[0] & c[0]);
    assign c[2] = g[1] | (p[1] & c[1]);
    assign c[3] = g[2] | (p[2] & c[2]);
    assign c[4] = g[3] | (p[3] & c[3]);


    assign sum = p ^ {c[3:0]};


    assign p_group = p[0] & p[1] & p[2] & p[3];
    assign g_group = g[3] | (g[2] & p[3]) | (g[1] & p[3] & p[2]) | (g[0] & p[3] & p[2] & p[1]);


    assign cout = c[4];
endmodule

module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);

    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
            p_red <= 0;
            p_yellow <= 0;
            p_green <= 0;
        end
        else begin
            case (state)
                idle: begin
                    p_red <= 0;
                    p_yellow <= 0;
                    p_green <= 0;
                    state <= s1_red;
                end
                s1_red: begin
                    p_red <= 1;
                    p_yellow <= 0;
                    p_green <= 0;
                    if (cnt == 3) begin
                        state <= s3_green;
                    end
                    else begin
                        state <= s1_red;
                    end
                end
                s2_yellow: begin
                    p_red <= 0;
                    p_yellow <= 1;
                    p_green <= 0;
                    if (cnt == 3) begin
                        state <= s1_red;
                    end
                    else begin
                        state <= s2_yellow;
                    end
                end
                s3_green: begin
                    p_red <= 0;
                    p_yellow <= 0;
                    p_green <= 1;
                    if (cnt == 3) begin
                        state <= s2_yellow;
                    end
                    else begin
                        state <= s3_green;
                    end
                end
            endcase
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 10;
        end
        else begin
            if (pass_request && green && (cnt > 10)) begin
                cnt <= 10;
            end
            else if (!green && p_green) begin
                cnt <= 60;
            end
            else if (!yellow && p_yellow) begin
                cnt <= 5;
            end
            else if (!red && p_red) begin
                cnt <= 10;
            end
            else begin
                cnt <= cnt - 1;
            end
        end
    end

    assign clock = cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            yellow <= 0;
            green <= 0;
        end
        else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end

endmodule

module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);

reg [31:0] product;
reg [4:0] count;
reg [15:0] multiplicand, multiplier;
reg done_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        product <= 32'b0;
        count <= 5'b0;
        multiplicand <= 16'b0;
        multiplier <= 16'b0;
        done_reg <= 1'b0;
    end
    else if (start) begin
        multiplicand <= ain;
        multiplier <= bin;
        count <= 16;
        done_reg <= 1'b0;
    end
    else if (count > 0) begin
        if (multiplier[0]) begin
            product <= product + {16'b0, multiplicand};
        end
        multiplier <= multiplier >> 1;
        count <= count - 1;
        if (count == 1) begin
            done_reg <= 1'b1;
        end
    end
end

assign yout = product;
assign done = done_reg;

endmodule

module signal_generator (
    input clk,
    input rst_n,
    output reg [4:0] wave
);

localparam UP_STATE = 2'b00;
localparam DOWN_STATE = 2'b01;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= 0;
        wave <= 0;
    end else begin
        case (state)
            UP_STATE: begin
                if (wave == 5'b11111) begin
                    state <= DOWN_STATE;
                end else begin
                    wave <= wave + 1;
                end
            end
            DOWN_STATE: begin
                if (wave == 5'b00000) begin
                    state <= UP_STATE;
                end else begin
                    wave <= wave - 1;
                end
            end
        endcase
    end
end

endmodule

