module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

    reg [0:0] cnt_50;
    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_50 <= 1'b0;
            CLK_50 <= 1'b0;
        end else begin
            cnt_50 <= ~cnt_50;
            CLK_50 <= ~CLK_50;
        end
    end

    reg [3:0] cnt_10;
    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_10 <= 4'd0;
            CLK_10 <= 1'b0;
        end else begin
            if (cnt_10 == 4'd9) begin
                cnt_10 <= 4'd0;
                CLK_10 <= ~CLK_10;
            end else begin
                cnt_10 <= cnt_10 + 1;
            end
        end
    end

    reg [6:0] cnt_100;
    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_100 <= 7'd0;
            CLK_1 <= 1'b0;
        end else begin
            if (cnt_100 == 7'd99) begin
                cnt_100 <= 7'd0;
                CLK_1 <= ~CLK_1;
            end else begin
                cnt_100 <= cnt_100 + 1;
            end
        end
    end

endmodule

module right_shifter (
    input clk,
    output reg [7:0] q,
    input d
);
    initial begin
        q = 8'b0;
    end

    always @(posedge clk) begin
        q <= (q >> 1);
        q[7] <= d;
    end
endmodule

module synchronizer (
    input 				clk_a,
    input 				clk_b,
    input 				arstn,
    input				brstn,
    input		[3:0]	data_in,
    input               data_en,
    output reg  [3:0] 	dataout
);

reg [3:0] data_reg;
always @(posedge clk_a or negedge arstn) begin
    if (~arstn) begin
        data_reg <= 4'd0;
    end else begin
        data_reg <= data_in;
    end
end

reg en_data_reg;
always @(posedge clk_a or negedge arstn) begin
    if (~arstn) begin
        en_data_reg <= 1'd0;
    end else begin
        en_data_reg <= data_en;
    end
end

reg en_clap_one;
reg en_clap_two;
always @(posedge clk_b or negedge brstn) begin
    if (~brstn) begin
        en_clap_one <= 1'd0;
        en_clap_two <= 1'd0;
    end else begin
        en_clap_one <= en_data_reg;
        en_clap_two <= en_clap_one;
    end
end

always @(posedge clk_b or negedge brstn) begin
    if (~brstn) begin
        dataout <= 4'd0;
    end else begin
        if (en_clap_two) begin
            dataout <= data_reg;
        end else begin
            dataout <= dataout;
        end
    end
end
endmodule

module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);

reg [9:0] accumulator;
reg [1:0] counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        accumulator <= 10'd0;
        counter <= 2'd0;
        valid_out <= 1'b0;
    end else if (valid_in) begin
        if (counter == 2'd3) begin
            accumulator <= accumulator + {2'b00, data_in};
            counter <= 2'd0;
            valid_out <= 1'b1;
        end else begin
            accumulator <= accumulator + {2'b00, data_in};
            counter <= counter + 2'd1;
            valid_out <= 1'b0;
        end
    end
end

assign data_out = accumulator;
endmodule

module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

localparam IDLE = 3'b000;
localparam LOAD = 3'b001;
localparam CALC = 3'b010;
localparam OUT  = 3'b011;

reg [2:0] state, next_state;
reg [15:0] mul_out_reg;
reg [15:0] temp [0:7];
reg [15:0] sum [0:7];
reg [7:0] mul_a_reg, mul_b_reg;
reg [2:0] mul_en_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        mul_en_out_reg <= 3'b0;
        mul_out_reg <= 16'b0;
    end else begin
        state <= next_state;
        mul_en_out_reg <= {mul_en_out_reg[1:0], mul_en_in};
    end
end

always @* begin
    case(state)
        IDLE: begin
            if(mul_en_in) begin
                next_state = LOAD;
            end else begin
                next_state = IDLE;
            end
        end

        LOAD: begin
            if(!mul_en_in) begin
                next_state = CALC;
            end else begin
                next_state = LOAD;
            end
        end

        CALC: begin
            if(mul_en_out_reg[2]) begin
                next_state = OUT;
            end else begin
                next_state = CALC;
            end
        end

        OUT: begin
            if(!mul_en_out_reg[2]) begin
                next_state = IDLE;
            end else begin
                next_state = OUT;
            end
        end

        default: next_state = IDLE;
    endcase
end

always @(posedge clk) begin
    if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end else begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
    end
end

genvar i;
generate
    for(i = 0; i < 8; i=i+1) begin
        assign temp[i] = {{8{mul_b_reg[i]}}, mul_a_reg} << i;
    end
endgenerate

always @(posedge clk) begin
    sum[0] <= temp[0];
    sum[1] <= temp[1] + temp[2];
    sum[2] <= temp[3] + temp[4];
    sum[3] <= temp[5] + temp[6];
    sum[4] <= temp[7];
    sum[5] <= sum[1] + sum[2];
    sum[6] <= sum[3] + sum[4];
    sum[7] <= sum[5] + sum[6];
end

always @(posedge clk) begin
    if (mul_en_out_reg[2]) begin
        mul_out_reg <= sum[0] + sum[7];
    end else begin
        mul_out_reg <= 16'b0;
    end
end

assign mul_out = mul_out_reg;

endmodule

module adder_pipe_64bit #(
    parameter DATA_WIDTH = 64,
    parameter STG_WIDTH = 16
) (
    input clk,
    input rst_n,
    input i_en,
    input [DATA_WIDTH-1:0] adda,
    input [DATA_WIDTH-1:0] addb,
    output [DATA_WIDTH:0] result,
    output reg o_en
);

    reg [DATA_WIDTH-1:0] adda_reg, addb_reg;
    reg [DATA_WIDTH:0] sum_reg;
    reg [STG_WIDTH-1:0] stage_en_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 0;
            addb_reg <= 0;
            sum_reg <= 0;
            stage_en_reg <= 0;
            o_en <= 0;
        end else begin
            adda_reg <= adda;
            addb_reg <= addb;
            sum_reg <= adda_reg + addb_reg;
            stage_en_reg <= {stage_en_reg[STG_WIDTH-2:0], i_en};
            o_en <= stage_en_reg[STG_WIDTH-1];
        end
    end

    assign result = sum_reg;

endmodule

module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);

parameter S0 = 3'b000;
parameter S1 = 3'b001;
parameter S2 = 3'b010;
parameter S3 = 3'b011;
parameter S4 = 3'b100;
parameter S5 = 3'b101;

reg [2:0] current_state, next_state;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        current_state <= S0;
    end else begin
        current_state <= next_state;
    end
end

always @(*) begin
    case(current_state)
        S0: begin
            if(IN == 1'b1) begin
                next_state = S1;
                MATCH = 1'b0;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S1: begin
            if(IN == 1'b0) begin
                next_state = S2;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
        S2: begin
            if(IN == 1'b0) begin
                next_state = S3;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
        S3: begin
            if(IN == 1'b1) begin
                next_state = S4;
                MATCH = 1'b0;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S4: begin
            if(IN == 1'b1) begin
                next_state = S5;
                MATCH = 1'b1;
            end else begin
                next_state = S0;
                MATCH = 1'b0;
            end
        end
        S5: begin
            if(IN == 1'b0) begin
                next_state = S2;
                MATCH = 1'b0;
            end else begin
                next_state = S1;
                MATCH = 1'b0;
            end
        end
    endcase
end
endmodule

module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

parameter IDLE = 2'b00;
parameter PULSE_START = 2'b01;
parameter PULSE_MIDDLE = 2'b10;
parameter PULSE_END = 2'b11;

reg [1:0] state;
reg [1:0] next_state;

always @(*) begin
    case (state)
        IDLE: begin
            if (data_in == 1'b1) next_state = PULSE_START; else next_state = IDLE;
        end

        PULSE_START: begin
            if (data_in == 1'b0) next_state = PULSE_MIDDLE; else next_state = PULSE_START;
        end

        PULSE_MIDDLE: begin
            if (data_in == 1'b1) next_state = PULSE_END; else next_state = IDLE;
        end

        PULSE_END: begin
            if (data_in == 1'b0) next_state = IDLE; else next_state = PULSE_START;
        end
    endcase
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) state <= IDLE; else state <= next_state;
end

always @(*) begin
    case (state)
        PULSE_END: begin
            if (data_in == 1'b0) data_out = 1'b1; else data_out = 1'b0;
        end
        default: begin
            data_out = 1'b0;
        end
    endcase
end
endmodule

module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

wire [3:0] ext_mul_a = {{(size){1'b0}}, mul_a};
wire [3:0] ext_mul_b = {{(size){1'b0}}, mul_b};

genvar i;
generate
    for (i = 0; i < size; i = i + 1) begin : gen_partial_products
        wire [3:0] partial_product;
        assign partial_product = (ext_mul_b[i]) ? (ext_mul_a << i) : 'd0;
    end
endgenerate

reg [7:0] sum_tmp1, sum_tmp2;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        sum_tmp1 <= 8'b0;
        sum_tmp2 <= 8'b0;
    end else begin
        sum_tmp1 <= (ext_mul_b[0] ? ext_mul_a : 8'b0) + (ext_mul_b[1] ? ext_mul_a << 1 : 8'b0);
        sum_tmp2 <= (ext_mul_b[2] ? ext_mul_a << 2 : 8'b0) + (ext_mul_b[3] ? ext_mul_a << 3 : 8'b0);
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_out <= 8'b0;
    end else begin
        mul_out <= sum_tmp1 + sum_tmp2;
    end
end
endmodule

module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output wire [WIDTH-1:0]	rdata
);

reg [ADDR_WIDTH:0] wptr, rptr, wptr_buff, wptr_syn, rptr_buff, rptr_syn;
wire [WIDTH-1:0] ram_rdata;
reg [WIDTH-1:0] ram_wdata;
reg wenc, renc;

dual_port_RAM #(.DEPTH(DEPTH), .WIDTH(WIDTH)) dual_port_ram_inst (
    .wclk(wclk),
    .wenc(wenc),
    .waddr(wptr_buff[ADDR_WIDTH-1:0]),
    .wdata(ram_wdata),
    .rclk(rclk),
    .renc(renc),
    .raddr(rptr_buff[ADDR_WIDTH-1:0]),
    .rdata(ram_rdata)
);

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr <= 0;
        wptr_buff <= 0;
        wptr_syn <= 0;
        wenc <= 1'b0;
    end else if (winc) begin
        wptr <= wptr + 1'b1;
        wptr_buff <= wptr_buff + 1'b1;
        wptr_syn <= wptr_syn + 1'b1;
        wenc <= 1'b1;
    end else begin
        wenc <= 1'b0;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr <= 0;
        rptr_buff <= 0;
        rptr_syn <= 0;
        renc <= 1'b0;
    end else if (rinc) begin
        rptr <= rptr + 1'b1;
        rptr_buff <= rptr_buff + 1'b1;
        rptr_syn <= rptr_syn + 1'b1;
        renc <= 1'b1;
    end else begin
        renc <= 1'b0;
    end
end

assign ram_wdata = wdata;
assign rdata = ram_rdata;
assign wfull = (wptr == {~rptr_syn[ADDR_WIDTH:ADDR_WIDTH-1], rptr_syn[ADDR_WIDTH-2:0]});
assign rempty = (rptr == wptr_syn);

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule

module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);
    reg [31:0] res;
    assign r = res[31:0];
    assign zero = (res[31:0] == 32'b0);
    assign negative = res[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
    always @(*) begin
        case (aluc)
            ADD: begin
                {carry, res[31:0]} = {a[31], a[31:0]} + {b[31], b[31:0]};
                overflow = (a[31] == b[31]) && (res[31] != a[31]);
            end
            ADDU: begin
                res[31:0] = a[31:0] + b[31:0];
                overflow = 1'b0;
            end
            SUB: begin
                {carry, res[31:0]} = {a[31], a[31:0]} - {b[31], b[31:0]};
                overflow = (a[31] != b[31]) && (res[31] != a[31]);
            end
            SUBU: begin
                res[31:0] = a[31:0] - b[31:0];
                overflow = 1'b0;
            end
            AND: res[31:0] = a[31:0] & b[31:0];
            OR: res[31:0] = a[31:0] | b[31:0];
            XOR: res[31:0] = a[31:0] ^ b[31:0];
            NOR: res[31:0] = ~(a[31:0] | b[31:0]);
            SLT: begin
                res[31:0] = (a[31:0] < b[31:0]) ? 32'b1 : 32'b0;
                overflow = 1'b0;
            end
            SLTU: begin
                res[31:0] = (a[31:0] < b[31:0]) ? 32'b1 : 32'b0;
                overflow = 1'b0;
            end
            SLL: res[31:0] = b[31:0] << a[4:0];
            SRL: res[31:0] = b[31:0] >> a[4:0];
            SRA: res[31:0] = b[31:0] >>> a[4:0];
            SLLV: res[31:0] = b[31:0] << a[4:0];
            SRLV: res[31:0] = b[31:0] >> a[4:0];
            SRAV: res[31:0] = b[31:0] >>> a[4:0];
            LUI: res[31:0] = {b[15:0], 16'b0};
            default: begin
                res[31:0] = 32'b0;
                carry = 1'b0;
                overflow = 1'b0;
            end
        endcase
    end
endmodule
